
class Vector {
    
    constructor(x,y){
        this.x = x
        this.y = y
    }
    
    static polar(angle,magnitude){
        var x = magnitude*Math.cos(angle)
        var y = magnitude*Math.sin(angle)
        return new Vector(x,y)
    }
    
    copy(){
        return new Vector(this.x,this.y)
    }
    
    // rotate around origin
    rotate(angle){
        var cos = Math.cos(angle)
        var sin = Math.sin(angle)
        return new Vector( this.x*cos-this.y*sin, this.y*cos+this.x*sin )
    }
    
    getAngle(){
        return Math.atan2( this.y, this.x )
    }
    
    getMagnitude(){
        return Math.sqrt( Math.pow(this.x,2) + Math.pow(this.y,2) )
    }
    
    // get unit vector with same angle
    normalize(){
        return this.mul( 1.0/this.getMagnitude() )
    }
    
    add( o ){
        return new Vector( this.x+o.x, this.y+o.y )
    }
    
    sub( o ){
        return new Vector( this.x-o.x, this.y-o.y )
    }
    
    mul( k ){
        return new Vector( this.x*k, this.y*k )
    }
}

// Continuous stroke path

class Segment{
    constructor( xy ){        
        this.xy = xy
        this.error = 0
    }
    
    reset(error,hard=false){ 
        if( isNaN(error ) ){
            console.log('poop')
        }
    
        this.fadeIndex = hard ? (Math.floor((.5-Math.random())*global.nFadeSteps)) : 0
        var r = .05//.2+Math.random()*.2
        this.exy = this.xy.map( p => {
            
            return [Math.random(),Math.random()]
            
            var a = Math.atan2( p[1]-.5, p[0]-.5 )
            return [.5+r*Math.cos(a),.5+r*Math.sin(a)]
        } )
        this.error = error
    }
    
    draw(g){
        g.moveTo(...this.p(0))
        g.bezierCurveTo(...this.p(1), ...this.p(2), ...this.p(3) )
    }
    
    // used in draw 
    p(i){ 
        
        // apply error
        var a = this.xy[i]
        var b = this.exy[i]
        return avg2(a,b,this.error)
    }
}

// shorthands
var pi = Math.PI
var pio2 = Math.PI/2
var twopi = 2*Math.PI
function v(){return new Vector(...arguments)}
function vp(){return Vector.polar(...arguments)}


function randRange(min,max){
    return min + rand()*(max-min)
}

function dist(a,b){
    var dx = a[0]-b[0]
    var dy = a[1]-b[1]
    return Math.sqrt( dx*dx + dy*dy )
}

function avg2(a,b,r=.5){
    return [
        a[0]*(1-r) + b[0]*r,
        a[1]*(1-r) + b[1]*r,
    ]
}

function shuffle(array) {
  let currentIndex = array.length,  randomIndex;
  while (currentIndex > 0) {
    randomIndex = Math.floor(Math.random() * currentIndex);
    currentIndex--;
    [array[currentIndex], array[randomIndex]] = [
      array[randomIndex], array[currentIndex]];
  }
  return array;
}

// 
// provides functions resetRand() and rand()
// 
// https://stackoverflow.com/a/47593316
//

var seed = null;
var rand = null;

function randomString(length) {
    let result = '';
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    const charactersLength = characters.length;
    let counter = 0;
    while (counter < length) {
      result += characters.charAt(Math.floor(Math.random() * charactersLength));
      counter += 1;
    }
    return result;
}

function resetRand(hard=false){
    if( hard || (seed==null) ){
        seed = cyrb128(randomString(10));
    }
    rand = sfc32(seed[0], seed[1], seed[2], seed[3])
}
    
function cyrb128(str) {
    let h1 = 1779033703, h2 = 3144134277,
        h3 = 1013904242, h4 = 2773480762;
    for (let i = 0, k; i < str.length; i++) {
        k = str.charCodeAt(i);
        h1 = h2 ^ Math.imul(h1 ^ k, 597399067);
        h2 = h3 ^ Math.imul(h2 ^ k, 2869860233);
        h3 = h4 ^ Math.imul(h3 ^ k, 951274213);
        h4 = h1 ^ Math.imul(h4 ^ k, 2716044179);
    }
    h1 = Math.imul(h3 ^ (h1 >>> 18), 597399067);
    h2 = Math.imul(h4 ^ (h2 >>> 22), 2869860233);
    h3 = Math.imul(h1 ^ (h3 >>> 17), 951274213);
    h4 = Math.imul(h2 ^ (h4 >>> 19), 2716044179);
    return [(h1^h2^h3^h4)>>>0, (h2^h1)>>>0, (h3^h1)>>>0, (h4^h1)>>>0];
}

function sfc32(a, b, c, d) {
    return function() {
      a >>>= 0; b >>>= 0; c >>>= 0; d >>>= 0;
      var t = (a + b) | 0;
      a = b ^ b >>> 9;
      b = c + (c << 3) | 0;
      c = (c << 21 | c >>> 11);
      d = d + 1 | 0;
      t = t + d | 0;
      c = c + t | 0;
      return (t >>> 0) / 4294967296;
    }
}


class Pattern {
    constructor(m,bx,by, all_xy){
              
        this.raw_xy = all_xy
              
        // break  segments  
        if( true ){
            var mind2 = .01
            var segs = []
            var batch = []
            all_xy.forEach( part => {
              part.forEach( p => {
                batch.push(p)
                if( batch.length > 1 ){
                    var a = batch[batch.length-2]
                    var b = batch[batch.length-1]
                    var d2 = Math.pow(a[0]-b[0],2) + Math.pow(a[1]-b[1],2)
                    if( d2 < 2e5*m ){
                        batch.pop()
                    }
                }
                if( batch.length >= 4 ){
                    segs.push(batch)
                    batch = [batch[1],batch[2],batch[3]]
                }
              })        
              batch = []
            })
            all_xy = segs
        }
        
        // break up big segments        
        if( false ){
            var targetCount = 50
            while( all_xy.length < targetCount ){
                var r = .4+Math.random()*.2
                var ls = this.longestSeg(all_xy)
                var i = Math.floor(ls.length*r)
                var ln = ls.splice(i,ls.length-i)
                for( var j = 0 ; j < 5 ; j ++ ){
                    if( j >= ln.length ) break
                    ls.push(ln[j])
                }
                all_xy.push( ln )
            }
        }
        
        this.segments = all_xy.map( xy => 
            new Segment(xy.map( p=> [
                m*p[0] + bx,
                m*p[1] + by
            ])) 
        )
        
        this.dt = 0
        this.t = 0
    }
    
    // used in setup.js
    reset(){
        this.error = global.startError
        this.dt = 0
        this.t = 0
        this.segments.forEach(s=>s.reset(this.error,hard=true))
    }
    
    // used in constructor
    longestSeg(all_xy){
        var result = []
        all_xy.forEach(s => {
            if( s.length > result.length ){
                result=s 
            }
        })
        return result
    }
    
    update(dt){
        this.dt = dt
        this.t += dt
        this.error -= global.dError*dt * (this.error/(.5*global.startError))
        if( this.error<global.minError ) this.error = global.minError
        
        // prepare for draw
        if( this.t > global.strokeDuration ) {
            this.segments.forEach(s => {
                s.fadeIndex += 1
                if( s.fadeIndex >= global.nFadeSteps ){
                    s.reset(this.error)
                }
            })
            this.t -= global.strokeDuration
            return
        }
    }
    
    draw(g, fadeIndex){
        this.segments.forEach( s => {
            if( s.fadeIndex != fadeIndex ) return
            s.draw(g)
        })
    }
}

