allPatterns = [
    butterflyPattern,
    dragonPattern,
    skullPattern,
    carPattern,
    atomPattern,
]
shuffle(allPatterns)
patternIndex = 0

function getNextPattern(){
    patternIndex += 1
    if( patternIndex >= allPatterns.length ){
        shuffle(allPatterns)
        patternIndex = 0
    }
    return allPatterns[patternIndex]
}

const global = {
    // graphics context
    canvas: null,
    ctx: null,
    
    // relate pixels to virtual units
    canvasOffsetX: 0,
    canvasOffsetY: 0,
    canvasScale: 0,

    // mouse
    canvasMousePos: v(0,0),     //pixels
    mousePos: v(0,0),           //internal units

    // 
    backgroundColor: 'white',
    alpha: .1,
    nFadeSteps: 20,
    strokeDuration: 100, //ms
    startThickness: .001, // thickness of newly drawn line
    dThickness: .0001, // increase in thickness per fade step
    
    // total time elapsed in milliseconds
    t: 0,
    startError: 0.5,
    dError: 2e-4, // decrease in error per ms
    minError: 0,
    
    
    //
    currentPattern: null,
    autoResetCountdown: 0,
    autoResetDelay: 12000,

    
    //debug
    //debugPoint: v(0,0),
}


    
    
// Render graphics
function draw(fps, t) {
   var ctx = global.ctx
   var canvas = global.canvas
    ctx.lineCap = 'round'
   
    //ctx.clearRect( 0, 0, canvas.width, canvas.height )
    for( var fi = 0 ; fi < global.nFadeSteps ; fi++ ){
        if( false && (fi == global.nFadeSteps-1) ){
            ctx.strokeStyle = global.backgroundColor
        } else {
            this.d = Math.floor(255*(fi/global.nFadeSteps))
            ctx.strokeStyle = `rgba(${d},${d},${d},${global.alpha})`
        }
        ctx.lineWidth = global.startThickness + global.dThickness*fi
        ctx.beginPath()
        global.currentPattern.draw(ctx,fi)
        ctx.stroke()
    }
    
    //debug
    //drawFilledChunks(ctx)
    
    //y += 30
    //ctx.fillText(`camera: ${cameraX.toFixed(2)}, ${cameraY.toFixed(2)}, ${zoomLevel.toFixed(2)}`, x, y);
    //y += 30
    //ctx.fillText(gameState, x, y);
    //y += 30 
    //ctx.fillText(`canvas pos: ${canvasMouseX}, ${canvasMouseY}`, x, y);
    //y += 30
    //ctx.fillText(`virtual pos: ${virtualMouseX}, ${virtualMouseY}`, x, y);
}

function updateMousePos(event){
    
    
    var rect = global.canvas.getBoundingClientRect();
    var scaleX = global.canvas.width / rect.width;
    var scaleY = global.canvas.height / rect.height;
    
    global.canvasMousePos = new Vector( 
        (event.clientX - rect.left) * scaleX, 
        (event.clientY - rect.top) * scaleY 
    
    )
    global.mousePos = new Vector( 
        virtualMouseX = (global.canvasMousePos.x-global.canvasOffsetX)/global.canvasScale, 
        virtualMouseY = (global.canvasMousePos.y-global.canvasOffsetY)/global.canvasScale
    )
}

function mouseMove(e){
    updateMousePos(e)
}

function mouseClick(e){
    updateMousePos(e)
    
    //global.debugPoint = global.mousePos
    resetGame()
}



function update(dt) {    
    global.t += dt
    
    global.currentPattern.update(dt)
    
    if( true ){
        global.autoResetCountdown -= dt
        if( global.autoResetCountdown < 0 ){
            resetGame()
        }
    }
}



// Initialize the game
function init() {
    var cvs = document.getElementById("gameCanvas");
    cvs.addEventListener("mousemove", mouseMove);
    cvs.addEventListener("click", mouseClick);
    global.canvas = cvs
    global.ctx = cvs.getContext("2d");
    
    resetRand()
    
    resetGame()
    requestAnimationFrame(gameLoop);
}


function resetGame(){
    resetRand(hard=true)
    global.autoResetCountdown = global.autoResetDelay
    global.t = 0
    fitToContainer()
    global.ctx.clearRect( 0, 0, global.canvas.width, global.canvas.height )
    global.currentPattern = getNextPattern()
    
    console.log( JSON.stringify(global.currentPattern.raw_xy, function(key, val) {
        return val.toFixed ? Number(val.toFixed(0)) : val;
    }))
    
    global.currentPattern.reset()
}

function fitToContainer(){
    
    var cvs = global.canvas
  cvs.style.width='100%';
  cvs.style.height='100%';  
  cvs.width  = cvs.offsetWidth;
  cvs.height = cvs.offsetHeight;
    
    var padding = 0; // (extra zoom IN) thickness of pixels CUT OFF around edges
    var dimension = Math.min(cvs.width, cvs.height) + padding*2;
    global.canvasScale = dimension;
    global.canvasOffsetX = (cvs.width - dimension) / 2;
    global.canvasOffsetY = (cvs.height - dimension) / 2;
    
    global.ctx.setTransform(global.canvasScale, 0, 0, 
        global.canvasScale, global.canvasOffsetX, global.canvasOffsetY);
    global.ctx.fillStyle = global.backgroundColor
    global.ctx.fillRect( 0, 0, cvs.width, cvs.height )
}



// Main game loop
let secondsPassed;
let oldTimeStamp;
let fps;

function gameLoop(timeStamp) {
    
    var msPassed = 0;
    if (oldTimeStamp) {
      msPassed = timeStamp - oldTimeStamp;
    }
    var secondsPassed = msPassed / 1000;
    oldTimeStamp = timeStamp;
    var fps = Math.round(1 / secondsPassed);


    msPassed = Math.min(msPassed,50)

    update(msPassed);
    draw(fps);

    requestAnimationFrame(gameLoop);
}


// Initialize the game
init();


